                title: t,
                desc: desc,
                url: absHref + '@lazyRule=.js:' + LAZY_CODE,
                col_type: 'text_1'
            });
            added++;
        }
        if (added === 0) d.push({title: '本节目未解析到集数', col_type: 'rich_text'});
        })();
        setResult(d);

